package main

import (
	"log"
	"os"
	"telegram-multiposting-bot/db"
)

func main() {
	log.Println("Starting Go API Server...")

	databaseURL := os.Getenv("DATABASE_URL")
	if databaseURL == "" {
		log.Fatal("DATABASE_URL environment variable is not set")
	}

	if err := db.InitDB(databaseURL); err != nil {
		log.Fatalf("Database initialization failed: %v", err)
	}

	log.Println("Go API Running successfully and database is updated!")
}

package db

import (
	"context"
	"database/sql"
	_ "embed"
	"fmt"
	"log"
	"time"

	_ "github.com/jackc/pgx/v5/stdlib"
)

//go:embed migrations.sql
var migrationsSQL string

var DB *sql.DB

// InitDB initializes the database pool and runs embedded migrations
func InitDB(databaseURL string) error {
	var err error
	DB, err = sql.Open("pgx", databaseURL)
	if err != nil {
		return fmt.Errorf("failed to open database: %w", err)
	}

	// Connection pool tuning
	DB.SetMaxOpenConns(25)
	DB.SetMaxIdleConns(10)
	DB.SetConnMaxLifetime(1 * time.Hour)

	// Verify connection
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()
	if err := DB.PingContext(ctx); err != nil {
		return fmt.Errorf("failed to ping database: %w", err)
	}

	log.Println("Database connection established successfully")

	// Run migrations
	if err := runMigrations(ctx); err != nil {
		return fmt.Errorf("failed to run migrations: %w", err)
	}

	return nil
}

func runMigrations(ctx context.Context) error {
	log.Println("Running database migrations...")
	tx, err := DB.BeginTx(ctx, nil)
	if err != nil {
		return fmt.Errorf("failed to begin migration transaction: %w", err)
	}
	defer tx.Rollback()

	// Acquire advisory lock using unique application key
	_, err = tx.ExecContext(ctx, "SELECT pg_advisory_xact_lock(723891);")
	if err != nil {
		return fmt.Errorf("failed to acquire migration advisory lock: %w", err)
	}

	_, err = tx.ExecContext(ctx, migrationsSQL)
	if err != nil {
		return fmt.Errorf("migration execution failed: %w", err)
	}

	if err := tx.Commit(); err != nil {
		return fmt.Errorf("failed to commit migration transaction: %w", err)
	}

	log.Println("Database migrations completed successfully")
	return nil
}
